class Solution:
    def checkPerfectNumber(self, num):
        if num <= 1:
            return False
        divisors = set()
        i = 1
        while i * i <= num:
            if num % i == 0:
                divisors.add(i)
                divisors.add(num // i)
            i += 1
        divisors.discard(num)
        return sum(divisors) == num

