var checkPerfectNumber = function(num) {
    if (num <= 1) return false;
    let total = 1;
    for (let i = 2; i * i <= num; i++) {
        if (num % i === 0) {
            total += i;
            const other = num / i;
            if (other !== i) total += other;
        }
    }
    return total === num;
};
